     1→import React, { useState } from 'react';
     2→import { Link, useNavigate } from 'react-router-dom';
     3→import { motion } from 'framer-motion';
     4→import { useAuth } from '../context/AuthContext';
     5→import { useSubscription } from '../context/SubscriptionContext';
     6→import { createCheckoutSession } from '../utils/api';
     7→import { useTranslation } from 'react-i18next';
     8→import './PricingPage.css';
     9→
    10→// Plan metadata — only non-translatable values here
    11→const PLAN_META = [
    12→  { id: 'free',      price: 0,   featureCount: 5, lockedCount: 4, hasBadge: false, highlight: false, priceId: null },
    13→  { id: 'grow',      price: 19,  featureCount: 8, lockedCount: 0, hasBadge: true,  highlight: true,  priceId: process.env.REACT_APP_STRIPE_GROW_PRICE_ID },
    14→  { id: 'scale',     price: 49,  featureCount: 7, lockedCount: 0, hasBadge: true,  highlight: false, priceId: process.env.REACT_APP_STRIPE_SCALE_PRICE_ID },
    15→  { id: 'evolution', price: 129,  featureCount: 8, lockedCount: 0, hasBadge: true,  highlight: false, priceId: process.env.REACT_APP_STRIPE_EVOLUTION_PRICE_ID },
    16→];
    17→
    18→// Comparison table — 4 columns: free, grow, scale, evolution
    19→const COMPARISON_ROWS = [
    20→  { idx: 0,  free: 'trial',    grow: 'unlimited', scale: 'unlimited', evolution: 'unlimited' },
    21→  { idx: 1,  free: '⚠️',      grow: '✅',        scale: '✅',        evolution: '✅' },
    22→  { idx: 2,  free: '❌',       grow: '✅',        scale: '✅',        evolution: '✅' },
    23→  { idx: 3,  free: '❌',       grow: '✅',        scale: '✅',        evolution: '✅' },
    24→  { idx: 4,  free: '❌',       grow: 'partial',   scale: 'partial',   evolution: '✅' },
    25→  { idx: 5,  free: '❌',       grow: '❌',        scale: '✅',        evolution: '✅' },
    26→  { idx: 6,  free: '❌',       grow: '❌',        scale: '✅',        evolution: '✅' },
    27→  { idx: 7,  free: '❌',       grow: '❌',        scale: '✅',        evolution: '✅' },
    28→  { idx: 8,  free: '❌',       grow: '❌',        scale: '❌',        evolution: '✅' },
    29→  { idx: 9,  free: '❌',       grow: '❌',        scale: '❌',        evolution: '✅' },
    30→  { idx: 10, free: 'email',    grow: 'priority',  scale: 'priority',  evolution: 'dedicated' },
    31→  { idx: 11, free: 'addon',    grow: 'addon',     scale: 'addon',     evolution: 'addon' },
    32→];
    33→
    34→const FAQ_COUNT = 6;
    35→
    36→const fadeUp = {
    37→  hidden: { opacity: 0, y: 20 },
    38→  visible: { opacity: 1, y: 0 },
    39→};
    40→
    41→const stagger = {
    42→  hidden: {},
    43→  visible: { transition: { staggerChildren: 0.1 } },
    44→};
    45→
    46→export default function PricingPage() {
    47→  const { currentUser } = useAuth();
    48→  const { subscription } = useSubscription();
    49→  const navigate = useNavigate();
    50→  const { t } = useTranslation();
    51→  const [loadingPlan, setLoadingPlan] = useState(null);
    52→  const [error, setError] = useState('');
    53→
    54→  async function handleAddonSelect() {
    55→    if (!currentUser) {
    56→      navigate('/auth?mode=register');
    57→      return;
    58→    }
    59→    const addonPriceId = process.env.REACT_APP_STRIPE_N8N_ADDON_PRICE_ID;
    60→    if (!addonPriceId || addonPriceId === 'undefined') {
    61→      setError('N8n add-on payment is not configured yet. Please add REACT_APP_STRIPE_N8N_ADDON_PRICE_ID to your environment variables.');
    62→      return;
    63→    }
    64→    setError('');
    65→    setLoadingPlan('addon');
    66→    try {
    67→      const { url } = await createCheckoutSession(addonPriceId, 'payment');
    68→      window.location.href = url;
    69→    } catch (err) {
    70→      setError(err.message || 'Failed to start checkout. Please try again.');
    71→    }
    72→    setLoadingPlan(null);
    73→  }
    74→
    75→  async function handlePlanSelect(plan) {
    76→    if (plan.id === 'free') {
    77→      navigate('/auth?mode=register');
    78→      return;
    79→    }
    80→
    81→    if (!currentUser) {
    82→      navigate('/auth?mode=register');
    83→      return;
    84→    }
    85→
    86→    if (!plan.priceId || plan.priceId === 'undefined') {
    87→      setError('Payment system is not configured yet. Please add Stripe price IDs to your environment variables.');
    88→      return;
    89→    }
    90→
    91→    setError('');
    92→    setLoadingPlan(plan.id);
    93→    try {
    94→      const { url } = await createCheckoutSession(plan.priceId);
    95→      window.location.href = url;
    96→    } catch (err) {
    97→      setError(err.message || 'Failed to start checkout. Please try again.');
    98→    }
    99→    setLoadingPlan(null);
   100→  }
   101→
   102→  function getPlanCta(plan) {
   103→    if (!currentUser && plan.id !== 'free') return t('pricing.signUpToStart', { defaultValue: 'Sign Up to Start' });
   104→    if (subscription === plan.id) return t('pricing.currentPlan', { defaultValue: '✅ Current Plan' });
   105→    if (plan.id === 'free' && subscription !== 'free') return t('pricing.downgrade', { defaultValue: 'Downgrade' });
   106→    return t(`pricing.plan.${plan.id}.cta`);
   107→  }
   108→
   109→  function translateVal(val) {
   110→    if (val === 'unlimited') return t('pricing.comparison.unlimited', { defaultValue: 'Unlimited' });
   111→    if (val === 'trial')     return t('pricing.comparison.trial',     { defaultValue: '14-day trial' });
   112→    if (val === 'partial')   return t('pricing.comparison.partial',   { defaultValue: '1 tool' });
   113→    if (val === 'email')     return t('pricing.comparison.email',     { defaultValue: 'Email' });
   114→    if (val === 'priority')  return t('pricing.comparison.priority',  { defaultValue: 'Priority' });
   115→    if (val === 'dedicated') return t('pricing.comparison.dedicated', { defaultValue: 'Dedicated' });
   116→    if (val === 'addon')     return t('pricing.comparison.addon',     { defaultValue: '➕ Add-on' });
   117→    return val;
   118→  }
   119→
   120→  return (
   121→    <div className="page">
   122→      <div className="pricing">
   123→        {/* Hero */}
   124→        <motion.div
   125→          className="pricing__hero container"
   126→          initial={{ opacity: 0, y: 30 }}
   127→          animate={{ opacity: 1, y: 0 }}
   128→          transition={{ duration: 0.6 }}
   129→        >
   130→          <span className="badge badge-primary">
   131→            {t('pricing.hero.badge', { defaultValue: 'Simple, Transparent Pricing' })}
   132→          </span>
   133→          <h1 className="pricing__title">
   134→            {t('pricing.hero.titlePre', { defaultValue: 'Choose Your' })}{' '}
   135→            <span className="gradient-text">{t('pricing.hero.titleHighlight', { defaultValue: 'Growth Plan' })}</span>
   136→          </h1>
   137→          <p className="pricing__subtitle">
   138→            {t('pricing.hero.subtitle', { defaultValue: "Start free. Upgrade when you're ready. No contracts, cancel anytime." })}
   139→          </p>
   140→        </motion.div>
   141→
   142→        {error && (
   143→          <div className="container">
   144→            <div className="alert alert-warning" style={{ marginBottom: '2rem' }}>
   145→              ⚠️ {error}
   146→            </div>
   147→          </div>
   148→        )}
   149→
   150→        {/* Plans */}
   151→        <div className="container">
   152→          <motion.div
   153→            className="pricing__plans pricing__plans--4"
   154→            initial="hidden"
   155→            animate="visible"
   156→            variants={stagger}
   157→          >
   158→            {PLAN_META.map((plan) => {
   159→              const features = Array.from({ length: plan.featureCount }, (_, i) =>
   160→                t(`pricing.plan.${plan.id}.feature.${i}`)
   161→              );
   162→              const locked = Array.from({ length: plan.lockedCount }, (_, i) =>
   163→                t(`pricing.plan.${plan.id}.locked.${i}`)
   164→              );
   165→
   166→              return (
   167→                <motion.div
   168→                  key={plan.id}
   169→                  className={`pricing__plan pricing__plan--${plan.id} ${subscription === plan.id ? 'pricing__plan--current' : ''}`}
   170→                  variants={fadeUp}
   171→                  whileHover={{ y: -6 }}
   172→                  transition={{ type: 'spring', stiffness: 300, damping: 25 }}
   173→                >
   174→                  <div className="pricing__plan-glow" />
   175→
   176→                  {plan.hasBadge && subscription !== plan.id && (
   177→                    <div className="pricing__plan-badge">
   178→                      {t(`pricing.plan.${plan.id}.badge`)}
   179→                    </div>
   180→                  )}
   181→
   182→                  {subscription === plan.id && (
   183→                    <div className="pricing__plan-badge pricing__plan-badge--current">
   184→                      {t('pricing.currentPlan', { defaultValue: '✅ Current Plan' })}
   185→                    </div>
   186→                  )}
   187→
   188→                  <div className="pricing__plan-header">
   189→                    <h2 className="pricing__plan-name">{t(`pricing.plan.${plan.id}.name`)}</h2>
   190→                    <p className="pricing__plan-desc">{t(`pricing.plan.${plan.id}.desc`)}</p>
   191→                  </div>
   192→
   193→                  <div className="pricing__plan-price">
   194→                    <span className="pricing__plan-amount">€{plan.price}</span>
   195→                    <div className="pricing__plan-period">
   196→                      {plan.price === 0
   197→                        ? t('pricing.forever', { defaultValue: 'forever free' })
   198→                        : t('pricing.month', { defaultValue: '/month' })}
   199→                    </div>
   200→                  </div>
   201→
   202→                  <button
   203→                    className={`btn btn-secondary pricing__plan-cta`}
   204→                    onClick={() => handlePlanSelect(plan)}
   205→                    disabled={subscription === plan.id || loadingPlan === plan.id}
   206→                  >
   207→                    {loadingPlan === plan.id ? (
   208→                      <><span className="spinner" /> {t('pricing.processing', { defaultValue: 'Processing...' })}</>
   209→                    ) : (
   210→                      getPlanCta(plan)
   211→                    )}
   212→                  </button>
   213→
   214→                  <div className="pricing__features">
   215→                    {features.map((f) => (
   216→                      <div key={f} className="pricing__feature pricing__feature--included">
   217→                        <span className="pricing__feature-icon">✅</span>
   218→                        <span>{f}</span>
   219→                      </div>
   220→                    ))}
   221→                    {locked.map((f) => (
   222→                      <div key={f} className="pricing__feature pricing__feature--locked">
   223→                        <span className="pricing__feature-icon">🔒</span>
   224→                        <span>{f}</span>
   225→                      </div>
   226→                    ))}
   227→                  </div>
   228→                </motion.div>
   229→              );
   230→            })}
   231→          </motion.div>
   232→        </div>
   233→
   234→        {/* N8n Add-on */}
   235→        <div className="container">
   236→          <motion.div
   237→            className="pricing__addon"
   238→            initial={{ opacity: 0, y: 20 }}
   239→            whileInView={{ opacity: 1, y: 0 }}
   240→            viewport={{ once: true, margin: '-60px' }}
   241→            transition={{ duration: 0.5 }}
   242→          >
   243→            <div className="pricing__addon-left">
   244→              <span className="badge badge-primary pricing__addon-badge">
   245→                {t('pricing.addon.badge', { defaultValue: '⚡ Add-on' })}
   246→              </span>
   247→              <h3 className="pricing__addon-title">
   248→                {t('pricing.addon.title', { defaultValue: 'N8n Automation' })}
   249→              </h3>
   250→              <p className="pricing__addon-desc">
   251→                {t('pricing.addon.desc', { defaultValue: 'Design powerful no-code automations using n8n — available for any plan.' })}
   252→              </p>
   253→              <ul className="pricing__addon-features">
   254→                {[0, 1, 2, 3].map((i) => (
   255→                  <li key={i}>✅ {t(`pricing.addon.feature.${i}`)}</li>
   256→                ))}
   257→              </ul>
   258→            </div>
   259→
   260→            <div className="pricing__addon-right">
   261→              <div className="pricing__addon-price">
   262→                <span className="pricing__addon-amount">
   263→                  {t('pricing.addon.price', { defaultValue: '€10' })}
   264→                </span>
   265→                <span className="pricing__addon-period">
   266→                  {t('pricing.addon.period', { defaultValue: '/ 10 workflows' })}
   267→                </span>
   268→              </div>
   269→              <p className="pricing__addon-renew">
   270→                {t('pricing.addon.renew', { defaultValue: 'No expiry · Works with any plan · Buy more when you need' })}
   271→              </p>
   272→              <button
   273→                className="btn btn-primary pricing__plan-cta"
   274→                onClick={handleAddonSelect}
   275→                disabled={loadingPlan === 'addon'}
   276→              >
   277→                {loadingPlan === 'addon' ? '...' : t('pricing.addon.cta', { defaultValue: 'Get Add-on →' })}
   278→              </button>
   279→            </div>
   280→          </motion.div>
   281→        </div>
   282→
   283→        {/* Comparison table */}
   284→        <div className="container">
   285→          <motion.div
   286→            className="pricing__comparison"
   287→            initial={{ opacity: 0, y: 30 }}
   288→            whileInView={{ opacity: 1, y: 0 }}
   289→            viewport={{ once: true, margin: '-80px' }}
   290→            transition={{ duration: 0.6 }}
   291→          >
   292→            <h2 className="pricing__comparison-title">
   293→              {t('pricing.comparison.title', { defaultValue: 'Full Feature Comparison' })}
   294→            </h2>
   295→            <div className="pricing__table-wrap">
   296→              <table className="pricing__table">
   297→                <thead>
   298→                  <tr>
   299→                    <th>{t('pricing.comparison.featureCol', { defaultValue: 'Feature' })}</th>
   300→                    <th className="pricing__th--free">{t('pricing.plan.free.name', { defaultValue: 'Free' })}</th>
   301→                    <th className="pricing__th--grow">{t('pricing.plan.grow.name', { defaultValue: 'Grow' })}</th>
   302→                    <th className="pricing__th--scale">{t('pricing.plan.scale.name', { defaultValue: 'Scale' })}</th>
   303→                    <th className="pricing__th--evolution">{t('pricing.plan.evolution.name', { defaultValue: 'Evolution' })}</th>
   304→                  </tr>
   305→                </thead>
   306→                <tbody>
   307→                  {COMPARISON_ROWS.map((row) => (
   308→                    <tr key={row.idx}>
   309→                      <td>{t(`pricing.comparison.row.${row.idx}`)}</td>
   310→                      <td className="pricing__td--free">{translateVal(row.free)}</td>
   311→                      <td className="pricing__td--grow">{translateVal(row.grow)}</td>
   312→                      <td className="pricing__td--scale">{translateVal(row.scale)}</td>
   313→                      <td className="pricing__td--evolution">{translateVal(row.evolution)}</td>
   314→                    </tr>
   315→                  ))}
   316→                </tbody>
   317→              </table>
   318→            </div>
   319→          </motion.div>
   320→        </div>
   321→
   322→        {/* FAQ */}
   323→        <div className="container pricing__faq">
   324→          <h2 className="pricing__comparison-title">
   325→            {t('pricing.faq.title', { defaultValue: 'Frequently Asked Questions' })}
   326→          </h2>
   327→          <div className="pricing__faq-grid">
   328→            {Array.from({ length: FAQ_COUNT }, (_, i) => (
   329→              <div key={i} className="pricing__faq-item">
   330→                <h4>{t(`pricing.faq.${i}.q`)}</h4>
   331→                <p>{t(`pricing.faq.${i}.a`)}</p>
   332→              </div>
   333→            ))}
   334→          </div>
   335→        </div>
   336→
   337→        {/* CTA */}
   338→        <div className="container pricing__bottom-cta">
   339→          <motion.div
   340→            className="pricing__cta-card"
   341→            initial={{ opacity: 0, y: 20 }}
   342→            whileInView={{ opacity: 1, y: 0 }}
   343→            viewport={{ once: true }}
   344→          >
   345→            <h2>
   346→              {t('pricing.cta.titlePre', { defaultValue: 'Ready to' })}{' '}
   347→              <span className="gradient-text">{t('pricing.cta.titleHighlight', { defaultValue: 'Get Started?' })}</span>
   348→            </h2>
   349→            <p>{t('pricing.cta.subtitle', { defaultValue: 'Join thousands of marketers, founders, and agencies growing with AI.' })}</p>
   350→            <Link to="/auth?mode=register" className="btn btn-primary btn-lg">
   351→              {t('pricing.cta.btn', { defaultValue: 'Start Free Today →' })}
   352→            </Link>
   353→          </motion.div>
   354→        </div>
   355→      </div>
   356→    </div>
   357→  );
   358→}
